/**
 * Extracts the decimal portion of a given decimal number and returns it as a String of integers.
 * If the number is a whole number, returns "0".
 * 
 * @param number the decimal number from which to extract the decimal portion
 * @return a String representing the decimal part (digits after the decimal point)
 */
public static String getDecimalPortion(double number) {
    // Handle the case where the number is negative
    boolean isNegative = number < 0;
    number = Math.abs(number);

    // Extract the integer part
    long integerPart = (long) number;

    // Get the decimal part as a double
    double decimalPart = number - integerPart;

    // Convert to string to avoid floating-point precision issues
    String numberStr = Double.toString(number);

    // Find the decimal point
    int decimalIndex = numberStr.indexOf('.');

    // If no decimal point, return "0"
    if (decimalIndex == -1) {
        return "0";
    }

    // Extract the digits after the decimal point
    String decimalDigits = numberStr.substring(decimalIndex + 1);

    // Remove trailing zeros
    decimalDigits = decimalDigits.replaceAll("0+$", "");

    // If all decimal digits were zero, return "0"
    if (decimalDigits.isEmpty()) {
        return "0";
    }

    return decimalDigits;
}
